from dataclasses import dataclass, field
from datetime import date

@dataclass
class DecisionRecord:
    incident_id: str
    review_date: date
    attendees: list[str]
    decisions: list[dict]   # each: {decision, owner, due_date, rationale}
    action_item_changes: list[dict]  # items escalated, reprioritised, or assigned new owner
    customer_comms_approved: bool
    policy_changes: list[str]
    follow_up_review_date: date | None  # set for repeat-failure incidents

    def publish_summary(self) -> str:
        lines = [
            f"Decision Record — Incident {self.incident_id}",
            f"Review Date: {self.review_date}",
            f"Attendees: {', '.join(self.attendees)}",
            "",
            "Decisions Made:",
        ]
        for d in self.decisions:
            lines.append(f"  [{d['owner']} by {d['due_date']}] {d['decision']}")
        if self.policy_changes:
            lines.append("")
            lines.append("Policy Changes:")
            for p in self.policy_changes:
                lines.append(f"  - {p}")
        return "\n".join(lines)
